<?php
$defaultFrom = isset($tgl_awal) && $tgl_awal ? $tgl_awal : date('Y-m-01');
$defaultTo = isset($tgl_akhir) && $tgl_akhir ? $tgl_akhir : date('Y-m-d');
$materials = iterator_to_array($db->query("SELECT kd_barang,nm_barang,satuan FROM barang WHERE kd_kategori IN ('K02','K03') AND COALESCE(status,1)=1 ORDER BY kd_barang LIMIT 500"));
$plants = iterator_to_array($db->query("SELECT id,plant_code,plant_name FROM erp_plant WHERE status='Aktif' ORDER BY plant_code"));
$storageLocations = iterator_to_array($db->query("SELECT s.id,s.plant_id,s.storage_code,s.storage_name,p.plant_code FROM erp_storage_location s LEFT JOIN erp_plant p ON p.id=s.plant_id WHERE s.status='Aktif' ORDER BY p.plant_code,s.storage_code"));
$storageBins = iterator_to_array($db->query("SELECT b.id,b.storage_location_id,b.bin_code,b.bin_name,s.storage_code FROM erp_storage_bin b LEFT JOIN erp_storage_location s ON s.id=b.storage_location_id WHERE b.status='Aktif' ORDER BY s.storage_code,b.bin_code"));
$summary = $db->fetch("SELECT
  (SELECT COUNT(*) FROM barang WHERE kd_kategori IN ('K02','K03')) material_count,
  (SELECT COALESCE(SUM(sl.qty_sisa),0) FROM stock_layer sl JOIN barang b ON b.kd_barang=sl.kode WHERE b.kd_kategori IN ('K02','K03') AND sl.qty_sisa>0) current_stock,
  (SELECT COUNT(DISTINCT dt.no_ref) FROM detail_transaksi dt JOIN barang b ON b.kd_barang=dt.kd_barang WHERE b.kd_kategori IN ('K02','K03') AND dt.document_date BETWEEN ? AND ?) movement_docs,
  (SELECT COALESCE(SUM(ABS(dt.qty)),0) FROM detail_transaksi dt JOIN barang b ON b.kd_barang=dt.kd_barang WHERE b.kd_kategori IN ('K02','K03') AND dt.document_date BETWEEN ? AND ? AND (dt.direction='OUT' OR dt.qty<0 OR dt.move_code IN ('102','122','201','221','261','262','551','601','602'))) qty_out", array($defaultFrom.' 00:00:00',$defaultTo.' 23:59:59',$defaultFrom.' 00:00:00',$defaultTo.' 23:59:59'));
function mbj_view_h($value) { return htmlspecialchars((string)$value, ENT_QUOTES, 'UTF-8'); }
?>
