    <div class="form-group"><label class="control-label col-lg-2"><?=customs_h('period','Periode');?></label><div class="col-lg-2"><div class="input-group date mbj-date"><input type="text" class="form-control" id="tgl_awal" value="<?=mbj_view_h($defaultFrom);?>" autocomplete="off"><span class="input-group-addon"><span class="glyphicon glyphicon-calendar"></span></span></div></div><div class="col-lg-2"><div class="input-group date mbj-date"><input type="text" class="form-control" id="tgl_akhir" value="<?=mbj_view_h($defaultTo);?>" autocomplete="off"><span class="input-group-addon"><span class="glyphicon glyphicon-calendar"></span></span></div></div><label class="control-label col-lg-1"><?=customs_h('material','Material');?></label><div class="col-lg-5"><select id="filter_material" class="form-control"><option value="">Semua Barang Jadi</option><?php foreach($materials as $m){ ?><option value="<?=mbj_view_h($m->kd_barang);?>"><?=mbj_view_h($m->kd_barang.' - '.$m->nm_barang.' | '.$m->satuan);?></option><?php } ?></select><div class="mbj-help">Kosongkan untuk semua barang jadi.</div></div></div>
    <div class="form-group"><label class="control-label col-lg-2"><?=customs_h('plant','Plant');?></label><div class="col-lg-2"><select id="filter_plant" class="form-control"><option value="">Semua Plant</option><?php foreach($plants as $p){ ?><option value="<?=intval($p->id);?>"><?=mbj_view_h($p->plant_code.' - '.$p->plant_name);?></option><?php } ?></select></div><label class="control-label col-lg-2"><?=customs_h('storage_location','Storage Location');?></label><div class="col-lg-2"><select id="filter_storage_location" class="form-control"><option value="">Semua SLoc</option><?php foreach($storageLocations as $s){ ?><option value="<?=intval($s->id);?>" data-plant-id="<?=intval($s->plant_id);?>"><?=mbj_view_h($s->plant_code.' / '.$s->storage_code.' - '.$s->storage_name);?></option><?php } ?></select></div><label class="control-label col-lg-1"><?=customs_h('storage_bin','Storage Bin');?></label><div class="col-lg-3"><select id="filter_storage_bin" class="form-control"><option value="">Semua Bin</option><?php foreach($storageBins as $b){ ?><option value="<?=intval($b->id);?>" data-storage-location-id="<?=intval($b->storage_location_id);?>"><?=mbj_view_h($b->storage_code.' / '.$b->bin_code.' - '.$b->bin_name);?></option><?php } ?></select></div></div>
    <div class="form-group"><label class="control-label col-lg-2"><?=customs_h('stock_type','Stock Type');?></label><div class="col-lg-2"><select id="filter_stock_type" class="form-control"><option value="">Semua</option><option value="UNRESTRICTED">Unrestricted</option><option value="QUALITY">Quality Inspection</option><option value="BLOCKED">Blocked</option></select></div><label class="control-label col-lg-2"><?=customs_h('search','Search');?></label><div class="col-lg-4"><input type="text" id="filter_keyword" class="form-control" placeholder="<?=customs_h('search_material_doc','Kode/nama material, dokumen, AJU, BPB, remark');?>"></div><div class="col-lg-2"><button type="button" class="btn btn-primary" id="btn_filter_mbj"><i class="fa fa-filter"></i> <?=customs_h('filter','Filter');?></button> <button type="button" class="btn btn-success" id="btn_excel_mbj"><i class="fa fa-file-excel-o"></i> <?=customs_h('excel','Excel');?></button> <button type="button" class="btn btn-default" id="btn_reset_mbj"><i class="fa fa-refresh"></i></button></div></div>
