<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script>
<script>
function mbjFilters(){return{tgl_awal:$('#tgl_awal').val(),tgl_akhir:$('#tgl_akhir').val(),material_code:$('#filter_material').val(),plant_id:$('#filter_plant').val(),storage_location_id:$('#filter_storage_location').val(),storage_bin_id:$('#filter_storage_bin').val(),stock_type:$('#filter_stock_type').val(),keyword:$('#filter_keyword').val()};}
function showMbjError(msg){$('.isi_warning_delete').text(msg||'Data mutasi barang jadi gagal dimuat.');$('.error_data_delete').fadeIn();}
$(function(){if($.fn.datepicker){$('.mbj-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_material,#filter_plant,#filter_storage_location,#filter_storage_bin,#filter_stock_type').select2({width:'100%',allowClear:true});}
$('#filter_plant').on('change',function(){var plant=$(this).val();$('#filter_storage_location option').each(function(){var op=$(this),p=op.data('plant-id');op.toggle(!p||!plant||String(p)===String(plant));});if(plant&&$('#filter_storage_location option:selected').data('plant-id')&&String($('#filter_storage_location option:selected').data('plant-id'))!==String(plant))$('#filter_storage_location').val('').trigger('change.select2');});
$('#filter_storage_location').on('change',function(){var loc=$(this).val();$('#filter_storage_bin option').each(function(){var op=$(this),l=op.data('storage-location-id');op.toggle(!l||!loc||String(l)===String(loc));});if(loc&&$('#filter_storage_bin option:selected').data('storage-location-id')&&String($('#filter_storage_bin option:selected').data('storage-location-id'))!==String(loc))$('#filter_storage_bin').val('').trigger('change.select2');});
var dt=$('#dtb_mutasi_barang_jadi').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:'<?=customs_h('export_data','Export Data');?>',buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:0,width:'48px',orderable:false,searchable:false,className:'mbj-center'},{targets:[4,5,6,7,8,9,10],className:'mbj-number'}],ajax:{url:'<?=base_admin();?>modul/mutasi_barang_jadi/mutasi_barang_jadi_data.php',type:'post',data:function(d){$.extend(d,mbjFilters());},error:function(xhr){console.log(xhr);showMbjError(<?=customs_js('finished_goods_mutation_load_failed','Data mutasi barang jadi gagal dimuat.');?>);}}});
$('#btn_filter_mbj').on('click',function(){$('#mbj_period_from').text($('#tgl_awal').val()||'-');$('#mbj_period_to').text($('#tgl_akhir').val()||'-');dt.draw();});$('#filter_keyword').on('keyup',function(e){if(e.keyCode===13)dt.draw();});$('#btn_excel_mbj').on('click',function(){window.location='<?=base_admin();?>modul/mutasi_barang_jadi/mutasi_barang_jadi_action.php?act=excel&'+$.param(mbjFilters());});
$('#btn_reset_mbj').on('click',function(){$('#tgl_awal').val('<?=$defaultFrom;?>');$('#tgl_akhir').val('<?=$defaultTo;?>');$('#mbj_period_from').text('<?=$defaultFrom;?>');$('#mbj_period_to').text('<?=$defaultTo;?>');$('#filter_keyword').val('');$('#filter_material,#filter_plant,#filter_storage_location,#filter_storage_bin,#filter_stock_type').val('').trigger('change');dt.draw();});
$(document).on('click','.mbj-detail-link',function(){var el=$(this);$('#isi_detail_mbj').html('<div class="text-center text-muted" style="padding:25px"><i class="fa fa-spinner fa-spin"></i> <?=customs_h('loading_detail','Memuat detail...');?></div>');$('#modal_detail_mbj').modal('show');$.post('<?=base_admin();?>modul/mutasi_barang_jadi/mutasi_barang_jadi_action.php?act=show_detail_pemasukan',{kd_barang:el.data('material'),type:el.data('type'),tgl_awal:$('#tgl_awal').val(),tgl_akhir:$('#tgl_akhir').val()},function(html){$('#isi_detail_mbj').html(html);}).fail(function(xhr){$('#isi_detail_mbj').html('<div class="alert alert-danger"><?=customs_h('detail_load_failed','Detail gagal dimuat.');?><br>'+xhr.responseText+'</div>');});});$(document).on('click','.hide_alert_notif',function(){$('.error_data_delete').hide();});});
</script>
